module RefModule (
    input clk,
    input reset_n,
    input d,
    output q,
    output q_bar);reg q_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset_n or posedge dbg_halt) begin
    if (~reset_n)
        q_reg <= 1'b0;
    else
        q_reg <= d;
end

assign q = q_reg;
assign q_bar = ~q_reg;

endmodule
